sql:
SELECT variety_id, SUM(quantity) AS total_quantity
FROM plant_orders
GROUP BY variety_id;

external_knowledge:
- "Sent on their journey to a new home" refers to orders with a status of 'shipped';
- "Fully paid for by their new caretakers" refers to orders with a payment status of 'paid';
- The care instructions include watering, sunlight, soil type, fertilizer, pruning, disease prevention, mulching, support requirements, and special care notes.

- 'Medium height' and 'Upright shape' are specific attributes of plant varieties;
- 'Retail orders' are a type of order in the plant orders table;
- 'Shipped' is a status indicating that the order has been completed and delivered.

- "variety_name" refers to the type of plant, like different types of flowers or trees;
- "total_quantity" is the sum of all quantities of a specific variety across different nurseries;
- "nurseries" are facilities where plants are grown and cared for.

sql:
SELECT COUNT(DISTINCT v.variety_id) AS total_varieties_with_inventory
FROM varieties v
INNER JOIN inventory i ON v.variety_id = i.variety_id;

SELECT hardiness
FROM varieties
WHERE maturity_period = (
  SELECT MAX(maturity_period)
  FROM varieties
);

